## D - Laser Marking ##
问题可以转换为不同组端点之间的移动的最小代价
由于 $n$ 最大6,考虑暴力
全排列 + 二进制枚举方向
```c++
void solve(){
    cin >> n >> S >> T;
    double sr = 0;
    for (int i = 0; i < n; i ++ ){
        int a, b, c, d;
        cin >> a >> b >> c >> d;
        tr[i] = {a, b, c, d};
        double D = sqrt(1.0 * (c - a) * (c - a) + (d - b) * (d - b));
        sr += D / T;
    }
    //线段移动T, 不同线段端点间移取S
    vector<int> v(n);
    for (int i = 0; i < n; i ++ ) v[i] = i;
    double ans = 1e9;
    do{
        for (int i = 0; i < (2 << n); i ++ ){ //枚举方向
            vector<pair<int, int>> p, q; //
            p.push_back({0, 0});
            for (int j = 0; j < n; j ++ ){
                if (i >> j & 1){ //正向
                    q.push_back({tr[v[j]].a, tr[v[j]].b});
                    p.push_back({tr[v[j]].c, tr[v[j]].d});
                }else{//反向
                    p.push_back({tr[v[j]].a, tr[v[j]].b});
                    q.push_back({tr[v[j]].c, tr[v[j]].d});
                }
            }
            double res = 0;
            //p->q
            for (int j = 0; j < n; j ++ ){ 
                double D = sqrt(1.0 * (p[j].x - q[j].x) * (p[j].x - q[j].x) + (p[j].y - q[j].y) * (p[j].y - q[j].y));
                res += D / S;
            }
            ans = min(ans, res);
        }
    }while (next_permutation(v.begin(), v.end()));
    ans += sr;
    cout << fixed << setprecision(7) << ans << '\n';
}
```

